def has_geminated_consonant(word):
    for i in range(len(word) - 1):
        if word[i] == word[i+1] and word[i].isalpha() and word[i].lower() not in 'aeiou':
            return True
    return False

# Example usage:
print(has_geminated_consonant("butter"))  # True (for English gemination)
print(has_geminated_consonant("hello"))   # False

This function checks for consecutive identical consonants (excluding vowels) to identify potential gemination.
